import{_ as a,o as s,c as i,ao as t}from"./chunks/framework.15pdmnck.js";const u=JSON.parse('{"title":"Verifying against MATLAB","description":"","frontmatter":{},"headers":[],"relativePath":"matlab_verify.md","filePath":"matlab_verify.md","lastUpdated":null}'),n={name:"matlab_verify.md"};function r(o,e,l,p,c,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="Verifying-against-MATLAB" tabindex="-1">Verifying against MATLAB <a class="header-anchor" href="#Verifying-against-MATLAB" aria-label="Permalink to &quot;Verifying against MATLAB {#Verifying-against-MATLAB}&quot;">​</a></h1><p>Mjolnir&#39;s correctness is gated by a <strong>differential oracle</strong> that runs each MATLAB snippet in an external engine (Octave or MATLAB) and compares the output variables to the converted Julia. By default the CI uses <strong>Octave</strong>, which is free, fast, and covers the vast majority of cases.</p><p>Real MATLAB catches a handful of things Octave gets wrong:</p><ul><li><p><code>string</code> (double-quoted) vs <code>char</code> array semantics</p></li><li><p><code>classdef</code> subtleties (property default values, <code>Dependent</code> properties, events)</p></li><li><p>Toolbox functions that Octave does not implement</p></li></ul><h2 id="Running-the-oracle-against-Octave-default" tabindex="-1">Running the oracle against Octave (default) <a class="header-anchor" href="#Running-the-oracle-against-Octave-default" aria-label="Permalink to &quot;Running the oracle against Octave (default) {#Running-the-oracle-against-Octave-default}&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>julia --project=test test/runtests.jl</span></span></code></pre></div><p>This is what CI runs. The Octave oracle is the definition of &quot;correct&quot; — any new mapping must keep it green.</p><h2 id="Running-against-MATLAB-collaborators" tabindex="-1">Running against MATLAB (collaborators) <a class="header-anchor" href="#Running-against-MATLAB-collaborators" aria-label="Permalink to &quot;Running against MATLAB (collaborators) {#Running-against-MATLAB-collaborators}&quot;">​</a></h2><p>If you have MATLAB installed, set the <code>MJOLNIR_ORACLE</code> environment variable:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># MATLAB only</span></span>
<span class="line"><span>MJOLNIR_ORACLE=matlab julia --project=test test/runtests.jl</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Octave AND MATLAB (runs each oracle case against both engines)</span></span>
<span class="line"><span>MJOLNIR_ORACLE=both julia --project=test test/runtests.jl</span></span></code></pre></div><p>The variable is silently ignored for engines that are not installed — you will see a skip notice rather than an error.</p><h2 id="Generating-IP-free-divergence-reports" tabindex="-1">Generating IP-free divergence reports <a class="header-anchor" href="#Generating-IP-free-divergence-reports" aria-label="Permalink to &quot;Generating IP-free divergence reports {#Generating-IP-free-divergence-reports}&quot;">​</a></h2><p>When converted Julia disagrees with the engine, <code>differential_report</code> builds an IP-free report you can share without disclosing proprietary source:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Mjolnir</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rep </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> differential_report</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(matlab_src, [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]; anonymize </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># rep[&quot;mismatched&quot;]  → names of variables that differ</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># rep[&quot;divergences&quot;] → per-variable type/size/first-diff-index summary</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># rep[&quot;converted_julia&quot;] → anonymized Julia output</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># rep[&quot;skeleton&quot;]    → node-kind s-expression (no user names or literals)</span></span></code></pre></div><p>With <code>anonymize=true</code> (the default) the report contains:</p><ul><li><p>Variable/function names replaced by <code>id1</code>, <code>id2</code>, … placeholders</p></li><li><p>Numeric and string literals stripped</p></li><li><p>Divergence described as type, size, first differing flat index, and magnitude — never raw values</p></li></ul><p>Set <code>anonymize=false</code> for local debugging where privacy is not a concern.</p><h2 id="Collaborator-quick-start" tabindex="-1">Collaborator quick-start <a class="header-anchor" href="#Collaborator-quick-start" aria-label="Permalink to &quot;Collaborator quick-start {#Collaborator-quick-start}&quot;">​</a></h2><p>Clone the repo, ensure MATLAB is on <code>PATH</code>, then:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>julia --project=. dev/matlab_verify.jl</span></span></code></pre></div><p>This runs <code>differential_report</code> over a set of representative snippets and writes IP-free JSON reports to <code>dev/reports/</code>. Share those files with the maintainer so MATLAB-specific mappings can be improved.</p><h2 id="Engine-API" tabindex="-1">Engine API <a class="header-anchor" href="#Engine-API" aria-label="Permalink to &quot;Engine API {#Engine-API}&quot;">​</a></h2><p>See the <a href="./api">API reference</a> for full documentation of <code>octave_available</code>, <code>matlab_available</code>, <code>available_engines</code>, <code>differential_report</code>, and <code>differential_report_json</code>.</p>`,23)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
